mapper.update:
UPDATE LECTURE
SET OPNN_YN     = #{opnnYn},
    LAST_MDFR_ID = #{userId}
WHERE LECTURE_SN = #{lectureSn}

UPDATE LECTURE
SET LOCK_YN     = #{lockYn},
    LAST_MDFR_ID = #{userId}
WHERE LECTURE_SN = #{lectureSn}

mapper.select:
select COURSE_SN, COURSE_NM,  RGTR_ID, LAST_MDFR_ID
from COURSE
where COURSE_SN = (select COURSE_SN from LECTURE where ATCH_FILE_ID = #{fileServerId} 
    fetch first 1 row only
)
